transform_js:
const categories = [...new Set(rawData.rows.map(r => r.category))];
const dims = ['dim1', 'dim2', 'dim3'];
const dimCount = dims.length;

// Layout configurations
const paddingLeft = 10;   // Left margin in percentage
const paddingRight = 5;   // Right margin in percentage
const paddingTop = 15;    // Top margin in percentage
const paddingBottom = 15; // Bottom margin in percentage

const gapX = 3;           // Horizontal gap between grids in percentage
const gapY = 3;           // Vertical gap between grids in percentage

// Usable area
const usableWidth = 100 - paddingLeft - paddingRight; 
const usableHeight = 100 - paddingTop - paddingBottom;

// Size of each grid
const gridWidth = (usableWidth - gapX * (dimCount - 1)) / dimCount;
const gridHeight = (usableHeight - gapY * (dimCount - 1)) / dimCount;

const seriesData = {};
categories.forEach(c => {
    seriesData[c] = [];
    rawData.rows.forEach(r => {
        if(r.category === c) {
            seriesData[c].push(r);
        }
    });
});

let grid = [];
let xAxis = [];
let yAxis = [];
let series = [];
let title = [];
let tooltip = [];

for (let i = 0; i < dimCount; i++) {
    for (let j = 0; j < dimCount; j++) {
        const xDim = dims[j];
        const yDim = dims[i];

        let gridLeft = paddingLeft + j * (gridWidth + gapX) + '%';
        let gridTop = paddingTop + i * (gridHeight + gapY) + '%';

        grid.push({
            left: gridLeft,
            top: gridTop,
            width: gridWidth + '%',
            height: gridHeight + '%'
        });

        xAxis.push({
            gridIndex: i * dimCount + j,
            type: 'value',
            name: i === dimCount - 1 ? xDim : '',
            nameLocation: 'middle',
            nameGap: 25,
            scale: true,
            axisLabel: {show: i === dimCount - 1, fontSize: 10},
            axisTick: {show: i === dimCount - 1},
            splitLine: {show: false},
            axisLine: {show: true}
        });

        yAxis.push({
            gridIndex: i * dimCount + j,
            type: 'value',
            name: j === 0 ? yDim : '',
            nameLocation: 'middle',
            nameGap: 35,
            scale: true,
            axisLabel: {show: j === 0, fontSize: 10},
            axisTick: {show: j === 0},
            splitLine: {show: false},
            axisLine: {show: true}
        });

        // Add series for each category
        categories.forEach((cat, catIdx) => {
            const dataPts = seriesData[cat].map(r => [r[xDim], r[yDim], r.category]);
            series.push({
                name: cat,
                type: 'scatter',
                xAxisIndex: i * dimCount + j,
                yAxisIndex: i * dimCount + j,
                data: dataPts,
                itemStyle: { opacity: 0.7 },
                symbolSize: 6
            });
        });
    }
}

title.push({
    text: 'Scatter Matrix (3x3)',
    left: 'center',
    top: '2%'
});

transformedData = {
    grid, xAxis, yAxis, series, title, categories
};

echarts_js:
const colors = ['#5470c6', '#91cc75', '#fac858', '#ee6666', '#73c0de', '#3ba272', '#fc8452', '#9a60b4', '#ea7ccc'];
const colorMap = {};
transformedData.categories.forEach((cat, i) => {
    colorMap[cat] = colors[i % colors.length];
});

option = {
    title: transformedData.title,
    legend: {
        data: transformedData.categories,
        top: '8%',
        left: 'center'
    },
    tooltip: {
        trigger: 'item',
        formatter: function(params) {
            return params.marker + params.data[2] + '<br/>' +
                   'X: ' + params.data[0] + '<br/>' +
                   'Y: ' + params.data[1];
        }
    },
    grid: transformedData.grid,
    xAxis: transformedData.xAxis,
    yAxis: transformedData.yAxis,
    series: transformedData.series.map(s => ({
        ...s,
        itemStyle: {
            color: colorMap[s.name],
            opacity: 0.7
        }
    }))
};
